const getLevel=p=>{for(let i=LEVELS.length-1;i>=0;i--)if(p>=LEVELS[i].min)return LEVELS[i];return LEVELS[0]};const getNextLevel=p=>{for(let i=0;i<LEVELS.length;i++)if(p<LEVELS[i].min)return LEVELS[i];return null};const getLevelProg=p=>{const c=getLevel(p),n=getNextLevel(p);if(!n)return{pct:100,rem:0};return{pct:Math.round(((p-c.min)/(n.min-c.min))*100),rem:n.min-p}};
